```ts
// Monitor available CPU capacity
cpuFree((freePercent) => {
  console.log(`Available CPU: ${(freePercent * 100).toFixed(1)}%`);

  if (freePercent < 0.2) {
    console.warn('CPU capacity low - consider load balancing');
  }
});

```

